  AND start_time >= #{start}
  AND start_time <= #{end}

SELECT COUNT(1)
FROM eb_attendance_apply_record
WHERE uid = #{uid}
  AND apply_type = #{applyType}
  AND start_time >= #{start}
  AND start_time <= #{end}

